Step 5 — Handle errors properly

try {
await sendEmail({
to: newUser.email,
subject: 'Verify your email',
html: `<a href="${verifyUrl}">Verify your email →</a>`
});
} catch (error) {
console.error('Failed to send welcome email:', error.message);
// Don't crash the signup flow — log it and move on
}

